package com.plantris.pastelist;

import static java.security.AccessController.getContext;

import android.Manifest;
import android.app.AlarmManager;
import android.app.NotificationChannel;
import android.app.NotificationManager;
import android.app.PendingIntent;
import android.content.Context;
import android.content.Intent;
import android.content.pm.PackageManager;
import android.os.Build;
import android.os.Bundle;
import android.util.Log;
import android.view.View;
import android.view.WindowInsetsController;
import android.widget.Button;

import androidx.appcompat.app.AppCompatActivity;
import androidx.core.content.ContextCompat;
import androidx.viewpager2.widget.ViewPager2;

import com.google.android.material.button.MaterialButton;

import java.time.LocalDate;


public class MainActivity extends AppCompatActivity {

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        ViewPager2 viewPager = findViewById(R.id.viewPager);
        MaterialButton btnTasks = findViewById(R.id.btnTasks);
        MaterialButton btnUpcoming = findViewById(R.id.btnUpcoming);

        viewPager.setAdapter(new MainPagerAdapter(this));
        viewPager.setUserInputEnabled(false);

        btnTasks.setOnClickListener(v -> viewPager.setCurrentItem(0, false));
        btnUpcoming.setOnClickListener(v -> viewPager.setCurrentItem(1, false));

        createNotificationChannel();

        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
            if (checkSelfPermission(android.Manifest.permission.POST_NOTIFICATIONS)
                    != PackageManager.PERMISSION_GRANTED) {
                requestPermissions(
                        new String[]{android.Manifest.permission.POST_NOTIFICATIONS},
                        100
                );
            }
        }
    }

    private void createNotificationChannel() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            NotificationChannel channel = new NotificationChannel(
                    "task_reminders",
                    "Task Reminders",
                    NotificationManager.IMPORTANCE_HIGH
            );

            NotificationManager manager = getSystemService(NotificationManager.class);
            if (manager == null) {
                Log.w("MainActivity", "NotificationManager unavailable; channel not created");
                return;
            }
            manager.createNotificationChannel(channel);
        }
    }
}

package com.plantris.pastelist;

import static java.security.AccessController.getContext;

import android.Manifest;
import android.app.AlarmManager;
import android.app.NotificationChannel;
import android.app.NotificationManager;
import android.app.PendingIntent;
import android.content.Context;
import android.content.Intent;
import android.content.pm.PackageManager;
import android.os.Build;
import android.os.Bundle;
import android.util.Log;
import android.view.View;
import android.view.WindowInsetsController;
import android.widget.Button;

import androidx.appcompat.app.AppCompatActivity;
import androidx.core.content.ContextCompat;
import androidx.viewpager2.widget.ViewPager2;

import com.google.android.material.button.MaterialButton;

import java.time.LocalDate;


public class MainActivity extends AppCompatActivity {

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        // Set status bar color and make icons dark for visibility on white background
        getWindow().setStatusBarColor(ContextCompat.getColor(this, android.R.color.white));
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.R) {
            getWindow().getInsetsController().setAppearance(WindowInsetsController.APPEARANCE_LIGHT_STATUS_BARS);
        } else {
            getWindow().getDecorView().setSystemUiVisibility(View.SYSTEM_UI_FLAG_LIGHT_STATUS_BAR);
        }

        ViewPager2 viewPager = findViewById(R.id.viewPager);
        MaterialButton btnTasks = findViewById(R.id.btnTasks);
        MaterialButton btnUpcoming = findViewById(R.id.btnUpcoming);

        viewPager.setAdapter(new MainPagerAdapter(this));
        viewPager.setUserInputEnabled(false);

        btnTasks.setOnClickListener(v -> viewPager.setCurrentItem(0, false));
        btnUpcoming.setOnClickListener(v -> viewPager.setCurrentItem(1, false));

        createNotificationChannel();

        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
            if (checkSelfPermission(android.Manifest.permission.POST_NOTIFICATIONS)
                    != PackageManager.PERMISSION_GRANTED) {
                requestPermissions(
                        new String[]{android.Manifest.permission.POST_NOTIFICATIONS},
                        100
                );
            }
        }
    }

    private void createNotificationChannel() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            NotificationChannel channel = new NotificationChannel(
                    "task_reminders",
                    "Task Reminders",
                    NotificationManager.IMPORTANCE_HIGH
            );

            NotificationManager manager = getSystemService(NotificationManager.class);
            if (manager == null) {
                Log.w("MainActivity", "NotificationManager unavailable; channel not created");
                return;
            }
            manager.createNotificationChannel(channel);
        }
    }
}

package com.plantris.pastelist;

import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.CheckBox;
import android.widget.TextView;

import androidx.annotation.NonNull;
import androidx.recyclerview.widget.RecyclerView;

import java.util.ArrayList;

public class SubtaskAdapter extends RecyclerView.Adapter<SubtaskAdapter.SubtaskVH> {

    private final ArrayList<SubtaskItem> items;

    public SubtaskAdapter(ArrayList<SubtaskItem> items) {
        this.items = items;
    }

    @NonNull
    @Override
    public SubtaskVH onCreateViewHolder(@NonNull ViewGroup parent, int viewType) {
        View view = LayoutInflater.from(parent.getContext())
                .inflate(R.layout.item_subtask, parent, false);
        return new SubtaskVH(view);
    }

    @Override
    public void onBindViewHolder(@NonNull SubtaskVH holder, int position) {
        SubtaskItem item = items.get(position);

        holder.checkBoxCompleted.setOnCheckedChangeListener(null);
        holder.checkBoxCompleted.setChecked(item.isCompleted());
        holder.textViewTitle.setText(item.getTitle());
        bindOptionalText(holder.textViewDescription, item.getDescription());
    }

    @Override
    public int getItemCount() {
        return items.size();
    }

    public void addItem(SubtaskItem item) {
        items.add(item);
        notifyItemInserted(items.size() - 1);
    }

    private void bindOptionalText(TextView textView, String value) {
        if (value == null || value.trim().isEmpty()) {
            textView.setText("");
            textView.setVisibility(View.GONE);
        } else {
            textView.setText(value);
            textView.setVisibility(View.VISIBLE);
        }
    }

    static class SubtaskVH extends RecyclerView.ViewHolder {
        final CheckBox checkBoxCompleted;
        final TextView textViewTitle;
        final TextView textViewDescription;

        SubtaskVH(@NonNull View itemView) {
            super(itemView);
            checkBoxCompleted = itemView.findViewById(R.id.subtaskViewCompleted);
            textViewTitle = itemView.findViewById(R.id.subtaskViewTaskName);
            textViewDescription = itemView.findViewById(R.id.subtaskDescription);
        }
    }
}

package com.plantris.pastelist;

import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.CheckBox;
import android.widget.TextView;

import androidx.annotation.NonNull;
import androidx.recyclerview.widget.RecyclerView;

import java.util.ArrayList;

public class SubtaskAdapter extends RecyclerView.Adapter<SubtaskAdapter.SubtaskVH> {

    public interface OnSubtaskCompletionChanged {
        void onSubtaskCompletionChanged(@NonNull SubtaskItem item, boolean isCompleted);
    }

    private final ArrayList<SubtaskItem> items;
    private final OnSubtaskCompletionChanged completionChanged;

    public SubtaskAdapter(ArrayList<SubtaskItem> items) {
        this(items, null);
    }

    public SubtaskAdapter(ArrayList<SubtaskItem> items, OnSubtaskCompletionChanged completionChanged) {
        this.items = items;
        this.completionChanged = completionChanged;
    }

    @NonNull
    @Override
    public SubtaskVH onCreateViewHolder(@NonNull ViewGroup parent, int viewType) {
        View view = LayoutInflater.from(parent.getContext())
                .inflate(R.layout.item_subtask, parent, false);
        return new SubtaskVH(view);
    }

    @Override
    public void onBindViewHolder(@NonNull SubtaskVH holder, int position) {
        SubtaskItem item = items.get(position);

        holder.checkBoxCompleted.setOnCheckedChangeListener(null);
        holder.checkBoxCompleted.setChecked(item.isCompleted());
        holder.textViewTitle.setText(item.getTitle());
        bindOptionalText(holder.textViewDescription, item.getDescription());

        holder.checkBoxCompleted.setOnCheckedChangeListener((buttonView, isChecked) -> {
            int adapterPosition = holder.getBindingAdapterPosition();
            if (adapterPosition == RecyclerView.NO_POSITION) {
                return;
            }
            SubtaskItem currentItem = items.get(adapterPosition);
            currentItem.setCompleted(isChecked);
            if (completionChanged != null) {
                completionChanged.onSubtaskCompletionChanged(currentItem, isChecked);
            }
        });
    }

    @Override
    public int getItemCount() {
        return items.size();
    }

    public void addItem(SubtaskItem item) {
        items.add(item);
        notifyItemInserted(items.size() - 1);
    }

    private void bindOptionalText(TextView textView, String value) {
        if (value == null || value.trim().isEmpty()) {
            textView.setText("");
            textView.setVisibility(View.GONE);
        } else {
            textView.setText(value);
            textView.setVisibility(View.VISIBLE);
        }
    }

    static class SubtaskVH extends RecyclerView.ViewHolder {
        final CheckBox checkBoxCompleted;
        final TextView textViewTitle;
        final TextView textViewDescription;

        SubtaskVH(@NonNull View itemView) {
            super(itemView);
            checkBoxCompleted = itemView.findViewById(R.id.subtaskViewCompleted);
            textViewTitle = itemView.findViewById(R.id.subtaskViewTaskName);
            textViewDescription = itemView.findViewById(R.id.subtaskDescription);
        }
    }
}

package com.plantris.pastelist;

import android.annotation.SuppressLint;
import android.os.Bundle;
import android.view.View;

import androidx.annotation.NonNull;
import androidx.annotation.Nullable;
import com.google.android.material.snackbar.Snackbar;
import androidx.appcompat.app.AppCompatActivity;
import androidx.fragment.app.Fragment;
import androidx.recyclerview.widget.LinearLayoutManager;
import androidx.recyclerview.widget.RecyclerView;

import java.time.LocalDate;
import java.time.format.DateTimeFormatter;
import java.util.ArrayList;

public class TaskFragment extends Fragment {

    private final ArrayList<TodoItem> todoList = new ArrayList<>();
    private TodoAdapter adapter;
    private boolean showCompletedOnly = false;

    public TaskFragment() {
        super(R.layout.task_view);
    }

    @SuppressLint("NotifyDataSetChanged")
    @Override
    public void onViewCreated(@NonNull View view, @Nullable Bundle savedInstanceState) {
        super.onViewCreated(view, savedInstanceState);

        RecyclerView recyclerView = view.findViewById(R.id.recyclerView);
        adapter = new TodoAdapter(
                todoList,
                (changedItem, isCompleted, position) -> {
                    if (getContext() == null) {
                        return;
                    }
                    // Mark as completed in DB (flag only)
                    try (DatabaseInsert dbHelper = new DatabaseInsert(getContext())) {
                        dbHelper.updateCompleted(changedItem.getId(), isCompleted);
                    }

                    // Show snackbar with Undo action. If undone, mark not completed and restore in list.
                    View parentView = requireView();
                    final int removedPos = position;
                    final TodoItem removedItem = changedItem;
                    Snackbar.make(parentView, "Task completed", Snackbar.LENGTH_LONG)
                            .setAction("Undo", v -> {
                                if (getContext() == null) return;
                                try (DatabaseInsert dbHelper = new DatabaseInsert(getContext())) {
                                    dbHelper.updateCompleted(removedItem.getId(), false);
                                }
                                // restore in-memory list and notify adapter
                                todoList.add(removedPos, removedItem);
                                adapter.notifyItemInserted(removedPos);
                            })
                            .show();
                },
                this::showEditTaskPopup,
                null
        );

        recyclerView.setLayoutManager(new LinearLayoutManager(requireContext()));
        recyclerView.setAdapter(adapter);

        loadTasks(false);

        view.findViewById(R.id.add_task_button).setOnClickListener(v -> showAddTaskSheet());
        view.findViewById(R.id.switch_views).setOnClickListener(v -> loadTasks(!showCompletedOnly));





    }

    @SuppressLint("NotifyDataSetChanged")
    private void loadTasks(boolean completedOnly) {
        showCompletedOnly = completedOnly;
        todoList.clear();

        if (getContext() == null) {
            return;
        }

        try (DatabaseInsert dbHelper = new DatabaseInsert(getContext())) {
            for (TodoItem item : dbHelper.readAllEntries()) {
                if (item.isCompleted() == completedOnly) {
                    todoList.add(item);
                }
            }
        }

        // Sort tasks by date in ascending order
        sortTasksByDate();

        adapter.notifyDataSetChanged();
    }

    private void sortTasksByDate() {
        todoList.sort((item1, item2) -> {
            LocalDate date1 = parseDate(item1.getDate());
            LocalDate date2 = parseDate(item2.getDate());

            // Handle null cases (unparseable dates go to the end)
            if (date1 == null && date2 == null) {
                return 0;
            }
            if (date1 == null) {
                return 1;
            }
            if (date2 == null) {
                return -1;
            }

            // Compare dates
            return date1.compareTo(date2);
        });
    }

    private LocalDate parseDate(String dateStr) {
        try {
            // Try yyyy-MM-dd format
            return LocalDate.parse(dateStr, DateTimeFormatter.ISO_LOCAL_DATE);
        } catch (Exception e1) {
            try {
                // Try dd/MM/yyyy format
                return LocalDate.parse(dateStr, DateTimeFormatter.ofPattern("dd.MM.yyyy"));
            } catch (Exception e2) {
                return null;
            }
        }
    }

    public void reloadTasks() {
        loadTasks(showCompletedOnly);
    }

    private void showAddTaskSheet() {
        if (!(requireActivity() instanceof AppCompatActivity)) {
            return;
        }

        AddTaskSheet.show((AppCompatActivity) requireActivity(), showCompletedOnly, item -> {
            todoList.add(item);
            adapter.notifyItemInserted(todoList.size() - 1);
        });
    }

    public void showEditTaskPopup(@NonNull TodoItem item, int position) {
        showEditTaskPopup(item);
    }

    public void showEditTaskPopup(@NonNull TodoItem item) {
        showEditTaskPopup(item, null);
    }

    public void showEditTaskPopup(@NonNull TodoItem item, @Nullable Runnable onAfterChange) {
        if (!(requireActivity() instanceof AppCompatActivity) || getContext() == null) {
            return;
        }

        EditTask.show((AppCompatActivity) requireActivity(), item, new EditTask.OnTaskActionListener() {
            @Override
            public void onDuplicateRequested(@NonNull TodoItem sourceItem) {
                if (getContext() == null) {
                    return;
                }
                try (DatabaseInsert dbHelper = new DatabaseInsert(getContext())) {
                    dbHelper.insertEntry(
                            sourceItem.getTitle(),
                            sourceItem.getDescription(),
                            sourceItem.getDate(),
                            sourceItem.getTime(),
                            sourceItem.isCompleted(),
                            sourceItem.getReminderMinutesBefore()
                    );
                }
                loadTasks(showCompletedOnly);
                if (onAfterChange != null) {
                    onAfterChange.run();
                }
            }

            @Override
            public void onDeleteConfirmed(@NonNull TodoItem sourceItem) {
                if (getContext() == null) {
                    return;
                }
                try (DatabaseInsert dbHelper = new DatabaseInsert(getContext())) {
                    dbHelper.deleteEntry(sourceItem.getId());
                }
                loadTasks(showCompletedOnly);
                if (onAfterChange != null) {
                    onAfterChange.run();
                }
            }

            @Override
            public void onSaveRequested(@NonNull TodoItem sourceItem) {
                if (getContext() == null) {
                    return;
                }
                try (DatabaseInsert dbHelper = new DatabaseInsert(getContext())) {
                    dbHelper.updateEntry(
                            sourceItem.getId(),
                            sourceItem.getTitle(),
                            sourceItem.getDescription(),
                            sourceItem.getDate(),
                            sourceItem.getTime()
                    );
                }
                loadTasks(showCompletedOnly);
                if (onAfterChange != null) {
                    onAfterChange.run();
                }
            }
        });
    }
}

