    @NonNull
    @Override
    public TodoVH onCreateViewHolder(@NonNull ViewGroup parent, int viewType) {
        View v = LayoutInflater.from(parent.getContext())
                .inflate(R.layout.item_todo, parent, false);
        return new TodoVH(v);
    }

    @Override
    public void onBindViewHolder(@NonNull TodoVH holder, int position) {
        TodoItem item = items.get(position);

        holder.textViewTitle.setText(item.getTitle());
        holder.textViewDescription.setText(item.getDescription());
        holder.textViewDate.setText(item.getDate());
        holder.textViewTime.setText(item.getTime());

        // Check if task is overdue and apply appropriate border and text
        boolean overdue = isOverdue(item);
        if (overdue) {
            holder.textViewOverdue.setText("OVERDUE");
            holder.textViewOverdue.setTextColor(holder.itemView.getContext().getColor(android.R.color.holo_red_dark));
            holder.itemView.setBackground(AppCompatResources.getDrawable(holder.itemView.getContext(), R.drawable.item_border_overdue));
        } else {
            holder.textViewOverdue.setText("");
            holder.itemView.setBackground(AppCompatResources.getDrawable(holder.itemView.getContext(), R.drawable.item_border));
        }

        holder.checkBoxDone.setOnCheckedChangeListener(null);
        holder.checkBoxDone.setChecked(item.isCompleted());


        holder.checkBoxDone.setOnCheckedChangeListener((buttonView, isChecked) -> {
            int adapterPos = holder.getBindingAdapterPosition();
            if (adapterPos != RecyclerView.NO_POSITION) {
                TodoItem changedItem = items.get(adapterPos);
                changedItem.setCompleted(isChecked);
                // notify parent (will update DB and show undo)
                if (onTodoCompletionChangedListener != null) {
                    onTodoCompletionChangedListener.onTodoCompletionChanged(changedItem, isChecked, adapterPos);
                }
                // remove from UI list
                items.remove(adapterPos);
                notifyItemRemoved(adapterPos);
            }
        });

        holder.itemView.setOnClickListener(v -> {
            int adapterPos = holder.getBindingAdapterPosition();
            if (adapterPos != RecyclerView.NO_POSITION && onTodoItemClickListener != null) {
                onTodoItemClickListener.onTodoItemClick(items.get(adapterPos), adapterPos);
            }
        });

        holder.itemView.setOnLongClickListener(v -> {
            int adapterPos = holder.getBindingAdapterPosition();
            if (adapterPos != RecyclerView.NO_POSITION && onTodoItemLongClickListener != null) {
                onTodoItemLongClickListener.onTodoItemLongClick(items.get(adapterPos), adapterPos, v);
                return true;
            }
            return false;
        });
    }

    @Override
    public int getItemCount() {
        return items.size();
    }

    /**
     * Check if a task date is in the past (overdue).
     * Expected date format: "yyyy-MM-dd" or "dd/MM/yyyy"
     */
    private boolean isOverdue(TodoItem item) {
        try {
            LocalDate today = LocalDate.now();
            String dateStr = item.getDate();

            // Try parsing with common formats
            LocalDate taskDate;
            try {
                // Try yyyy-MM-dd format
                taskDate = LocalDate.parse(dateStr, DateTimeFormatter.ISO_LOCAL_DATE);
            } catch (Exception e1) {
                try {
                    // Try dd/MM/yyyy format
                    taskDate = LocalDate.parse(dateStr, DateTimeFormatter.ofPattern("dd/MM/yyyy"));
                } catch (Exception e2) {
                    // If both fail, return false (not overdue)
                    return false;
                }
            }

            return taskDate.isBefore(today);
        } catch (Exception e) {
            return false;
        }
    }

    public static class TodoVH extends RecyclerView.ViewHolder {
        final CheckBox checkBoxDone;
        final TextView textViewTitle;
        final TextView textViewDescription;
        final TextView textViewDate;
        final TextView textViewTime;
        final TextView textViewOverdue;

        TodoVH(@NonNull View itemView) {
            super(itemView);
            checkBoxDone = itemView.findViewById(R.id.checkBoxDone);
            textViewTitle = itemView.findViewById(R.id.textViewTitle);
            textViewDescription = itemView.findViewById(R.id.textViewDescription);
            textViewDate = itemView.findViewById(R.id.textViewDate);
            textViewTime = itemView.findViewById(R.id.textViewTime);
            textViewOverdue = itemView.findViewById(R.id.textViewOverdue);

        }
    }




}

package com.plantris.pastelist;

import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.CheckBox;
import android.widget.LinearLayout;
import android.widget.TextView;
import android.widget.ImageView;

import androidx.annotation.NonNull;
import androidx.recyclerview.widget.RecyclerView;

import java.time.LocalDate;
import java.time.format.DateTimeFormatter;
import java.util.ArrayList;
import java.util.Collections;
import java.util.List;
import java.util.Locale;
import java.util.Map;

public class UpcomingDateAdapter extends RecyclerView.Adapter<UpcomingDateAdapter.UpcomingDateViewHolder> {

    private final ArrayList<LocalDate> upcomingDates = new ArrayList<>();
    private final Map<LocalDate, List<TodoItem>> tasksByDate = new java.util.HashMap<>();
    private final Map<LocalDate, String> dateLabels = new java.util.HashMap<>();
    private final DateTimeFormatter dayFormatter = DateTimeFormatter.ofPattern("EEEE", Locale.getDefault());
    private final DateTimeFormatter numberFormatter = DateTimeFormatter.ofPattern("dd", Locale.getDefault());
    private final DateTimeFormatter monthFormatter = DateTimeFormatter.ofPattern("MMM", Locale.getDefault());
    private DatabaseInsert databaseInsert;
    private OnTaskCompletedListener onTaskCompletedListener;

    public interface OnTaskCompletedListener {
        void onTaskCompleted();
    }

    public void setData(@NonNull List<LocalDate> dates, @NonNull Map<LocalDate, List<TodoItem>> groupedTasks, @NonNull Map<LocalDate, String> labels) {
        upcomingDates.clear();
        upcomingDates.addAll(dates);
        tasksByDate.clear();
        tasksByDate.putAll(groupedTasks);
        dateLabels.clear();
        dateLabels.putAll(labels);
        notifyDataSetChanged();
    }

    public void setDatabaseInsert(DatabaseInsert databaseInsert) {
        this.databaseInsert = databaseInsert;
    }

    public void setOnTaskCompletedListener(OnTaskCompletedListener listener) {
        this.onTaskCompletedListener = listener;
    }

    @NonNull
    @Override
    public UpcomingDateViewHolder onCreateViewHolder(@NonNull ViewGroup parent, int viewType) {
        View view = LayoutInflater.from(parent.getContext())
                .inflate(R.layout.item_upcoming_task_date, parent, false);
        return new UpcomingDateViewHolder(view);
    }

    @Override
    public void onBindViewHolder(@NonNull UpcomingDateViewHolder holder, int position) {
        LocalDate date = upcomingDates.get(position);

        // Check if there's a special label for this date (Today, Tomorrow, etc.)
        String dayLabel = dateLabels.getOrDefault(date, date.format(dayFormatter));
        holder.upcomingViewDay.setText(dayLabel + ",");
        holder.upcomingViewDateNumber.setText(date.format(numberFormatter));
        holder.upcomingViewMonth.setText(date.format(monthFormatter));
        holder.upcomingTaskContainer.removeAllViews();

        List<TodoItem> tasksForDate = tasksByDate.getOrDefault(date, Collections.emptyList());
        LayoutInflater inflater = LayoutInflater.from(holder.itemView.getContext());
        for (TodoItem task : tasksForDate) {
            View taskView = inflater.inflate(R.layout.item_upcoming_task, holder.upcomingTaskContainer, false);
            TextView taskName = taskView.findViewById(R.id.upcomingViewTaskName);
            TextView taskTime = taskView.findViewById(R.id.upcomingViewTaskTime);
            CheckBox taskCheckbox = taskView.findViewById(R.id.upcomingTaskViewCompleted);
            LinearLayout timeContainer = taskView.findViewById(R.id.timeContainer);

            taskName.setText(task.getTitle());
            String time = task.getTime() == null ? "" : task.getTime();
            taskTime.setText(time);
            taskCheckbox.setChecked(task.isCompleted());

            // Hide time container if no time is set
            if (time.isEmpty()) {
                timeContainer.setVisibility(View.GONE);
            } else {
                timeContainer.setVisibility(View.VISIBLE);
            }

            // Set checkbox listener to update database
            taskCheckbox.setOnCheckedChangeListener((buttonView, isChecked) -> {
                if (databaseInsert != null) {
                    databaseInsert.updateCompleted(task.getId(), isChecked);
                    task.setCompleted(isChecked);
                    if (onTaskCompletedListener != null) {
                        onTaskCompletedListener.onTaskCompleted();
                    }
                }
            });

            holder.upcomingTaskContainer.addView(taskView);
        }
    }

    @Override
    public int getItemCount() {
        return upcomingDates.size();
    }

    static class UpcomingDateViewHolder extends RecyclerView.ViewHolder {
        final TextView upcomingViewDay;
        final TextView upcomingViewDateNumber;
        final TextView upcomingViewMonth;
        final LinearLayout upcomingTaskContainer;

        UpcomingDateViewHolder(@NonNull View itemView) {
            super(itemView);
            upcomingViewDay = itemView.findViewById(R.id.upcomingViewDay);
            upcomingViewDateNumber = itemView.findViewById(R.id.upcomingViewDateNumber);
            upcomingViewMonth = itemView.findViewById(R.id.upcomingViewMonth);
            upcomingTaskContainer = itemView.findViewById(R.id.upcomingTaskContainer);
        }
    }
}

package com.plantris.pastelist;

import android.view.LayoutInflater;
